const keys = $input.first().json.keys || [];
if (!keys.length) {
  return [{ json: { error: 'no_runs_found', message: 'Nenhuma run encontrada em helena:eval:results:*' } }];
}
// Sort descending (latest first)
keys.sort().reverse();
const latestKey = keys[0];
return [{ json: { latest_key: latestKey, all_keys: keys, total_runs: keys.length } }];

const item = $input.first().json;
const raw = item.run_results_raw;

if (!raw) {
  return [{ json: { error: 'empty_run', message: 'Run sem dados' } }];
}

// Redis LRANGE returns array if GET propertyName was used on a list
let results = [];
try {
  if (Array.isArray(raw)) {
    results = raw.map(r => typeof r === 'string' ? JSON.parse(r) : r);
  } else if (typeof raw === 'string') {
    results = [JSON.parse(raw)];
  }
} catch(e) {
  return [{ json: { error: 'parse_failure', detail: e.message, raw_preview: String(raw).substring(0, 200) } }];
}

if (results.length === 0) {
  return [{ json: { error: 'no_results', message: 'Run vazia' } }];
}

// Aggregate
const total = results.length;
const passCount = results.filter(r => r.status === 'PASS').length;
const partialCount = results.filter(r => r.status === 'PARTIAL').length;
const failCount = results.filter(r => r.status === 'FAIL').length;

const passRate = Math.round((passCount / total) * 1000) / 10;
const failRate = Math.round((failCount / total) * 1000) / 10;

// By category
const categories = {};
for (const r of results) {
  if (!categories[r.category]) {
    categories[r.category] = { total: 0, pass: 0, partial: 0, fail: 0 };
  }
  const c = categories[r.category];
  c.total++;
  if (r.status === 'PASS') c.pass++;
  else if (r.status === 'PARTIAL') c.partial++;
  else c.fail++;
}
for (const cat of Object.keys(categories)) {
  const c = categories[cat];
  c.pass_rate = Math.round((c.pass / c.total) * 1000) / 10;
}

// Tool accuracy: tool_intention matches expected (or both null)
let toolCorrect = 0;
let toolApplicable = 0;
for (const r of results) {
  const expectedTools = r.expect?.tools || [];
  toolApplicable++;
  if (r.checks?.tool_correct === true) toolCorrect++;
}
const toolAccuracy = toolApplicable > 0 ? Math.round((toolCorrect / toolApplicable) * 1000) / 10 : 0;

// Latency stats
const latencies = results.map(r => r.latency_ms || 0).filter(l => l > 0);
const avgLatency = latencies.length ? Math.round(latencies.reduce((a,b) => a+b, 0) / latencies.length) : 0;
const maxLatency = latencies.length ? Math.max(...latencies) : 0;

// Failed tests detail
const failures = results
  .filter(r => r.status === 'FAIL' || r.status === 'PARTIAL')
  .map(r => ({
    test_id: r.test_id,
    category: r.category,
    status: r.status,
    prompt: r.prompt,
    expected_tools: r.expect?.tools,
    actual_tool: r.tool_intention,
    reasoning: r.reasoning?.substring(0, 100)
  }));

// Regression detection: placeholder for cross-run comparison
const regression = { note: 'Comparação cross-run disponível quando houver 2+ runs armazenadas' };

return [{
  json: {
    run_id: results[0].run_id,
    workflow_version: results[0].workflow_version,
    model: results[0].model,
    timestamp: new Date().toISOString(),
    summary: {
      total,
      pass: passCount,
      partial: partialCount,
      fail: failCount,
      pass_rate_percent: passRate,
      fail_rate_percent: failRate
    },
    by_category: categories,
    tool_accuracy_percent: toolAccuracy,
    latency_ms: { avg: avgLatency, max: maxLatency },
    failures,
    regression,
    health: passRate >= 80 ? 'HEALTHY' : passRate >= 60 ? 'DEGRADED' : 'CRITICAL'
  }
}];
